import{_ as a,o as e,c as r,a2 as o}from"./chunks/framework.e-meDy3u.js";const u=JSON.parse('{"title":"总览与方案背景","description":"","frontmatter":{},"headers":[],"relativePath":"overview.md","filePath":"overview.md"}'),d={name:"overview.md"};function s(h,t,n,i,l,p){return e(),r("div",null,[...t[0]||(t[0]=[o('<h1 id="总览与方案背景" tabindex="-1">总览与方案背景 <a class="header-anchor" href="#总览与方案背景" aria-label="Permalink to &quot;总览与方案背景&quot;">​</a></h1><p class="hqq-lede">以下是七道核心问题及对应的方案思路，供参阅。</p><h2 id="昊七七的现状与方案出发点" tabindex="-1">昊七七的现状与方案出发点 <a class="header-anchor" href="#昊七七的现状与方案出发点" aria-label="Permalink to &quot;昊七七的现状与方案出发点&quot;">​</a></h2><p>昊七七在抖音速食面热销榜排第二，打法已经被市场验证。方案的出发点只有一个：<strong>把已经跑通的东西做得更稳、更省人、更可复制</strong>，而不是重新换打法。</p><p>素材方面的机会在于：赢过的内容散在各个人手里和各个群里，缺少结构化沉淀。一旦整理成资产库，既能让自有私店的投放决策提速，又能把这套素材弹药放大给代理网络——一次整理，多方受益。</p><hr><h2 id="方案的主线" tabindex="-1">方案的主线 <a class="header-anchor" href="#方案的主线" aria-label="Permalink to &quot;方案的主线&quot;">​</a></h2><p>一条线，三步，每步等上一步跑出结果再做。</p><p><strong>第一步：搭库，先服务自有私店。</strong> 把已经验证过的爆款素材整理进一个结构化的资产库，按卖点、人群、场景排名，直接指导自家私店的投放决策。这一步入职就能开始，不依赖任何外部配合。</p><p><strong>第二步：去人肉，上推理层。</strong> 用脚本把数据回收自动化，用浏览器插件把取数自动化，让真正需要判断的地方——聚类用户反馈、归因分析、生成假设——才交给 AI 来做。</p><p><strong>第三步：放大给代理网络。</strong> 私店跑出成绩单之后，把这套库和方法论推给代理店。样板在手，代理才有理由跟进。</p><hr><h2 id="几个还没确认的前提" tabindex="-1">几个还没确认的前提 <a class="header-anchor" href="#几个还没确认的前提" aria-label="Permalink to &quot;几个还没确认的前提&quot;">​</a></h2><p>这三点会在入职第一周核实，方案的结论不依赖猜测。</p><table tabindex="0"><thead><tr><th>编号</th><th>待确认</th><th>影响哪里</th><th>Plan B</th></tr></thead><tbody><tr><td>Q-C</td><td>自有私店的投放体量有多大？我第一周能拿到数据吗？</td><td>整条主线的起跑点</td><td>若私店体量小，改用 1-2 个最配合的代理跑样板，逻辑不变</td></tr><tr><td>Q-A</td><td>代理是挂昊七七链接分销，还是自己开店各自运营？</td><td>第三步放大层怎么铺（主动推还是做成货架）</td><td>两手准备，详见附录</td></tr><tr><td>Q-B</td><td>公司的赢建立在固定打法上，还是靠少数人的经验判断？</td><td>Q1、Q7 的价值表述方式</td><td>两种情况表述不同，框架不变</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">为什么 Q-C 最关键</p><p>整条&quot;先私店样板、再代理放大&quot;的主线都压在&quot;私店有可跑的体量&quot;这个前提上。入职第一天就确认，不拖。</p></div><hr><h2 id="贯穿全案的核心立场" tabindex="-1">贯穿全案的核心立场 <a class="header-anchor" href="#贯穿全案的核心立场" aria-label="Permalink to &quot;贯穿全案的核心立场&quot;">​</a></h2><p>昊七七这套打法已经被市场验证，方案不动它。目标是把散在个人和群里的赢法沉淀下来，让它更省人、更能被更多人复用。加固地基，放大已有的优势。</p>',19)])])}const _=a(d,[["render",s]]);export{u as __pageData,_ as default};
